import React from 'react';
export default function Dashboard() {
  return (
    <div style={{ padding: '40px', color: '#fff' }}>
      <h1>🏋️ Dashboard</h1>
      <p style={{ color: '#888', marginTop: '8px' }}>Welcome to GymVision AI!</p>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '16px', marginTop: '32px' }}>
        {['Workouts Done', 'Calories Burned', 'Streak'].map((item, i) => (
          <div key={i} style={{ background: '#1a1a1a', padding: '24px', borderRadius: '12px' }}>
            <p style={{ color: '#888' }}>{item}</p>
            <h2 style={{ color: '#6c63ff', marginTop: '8px' }}>{['12', '4,200', '7 days'][i]}</h2>
          </div>
        ))}
      </div>
    </div>
  );
}
